const raw = $input.item.json.choices[0].message.content;

try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const data = JSON.parse(cleaned);

  const required = ['video_animation_prompt', 'post_title', 'post_description', 'comment_bait', 'hashtags'];
  for (const field of required) {
    if (!data[field]) throw new Error(`Missing field: ${field}`);
  }

  const platforms = ['instagram', 'tiktok', 'facebook', 'pinterest'];
  for (const p of platforms) {
    if (!data.hashtags[p] || !Array.isArray(data.hashtags[p])) {
      throw new Error(`Missing hashtags.${p}`);
    }
  }

  // === LOCK THE CTA ===
  const FIXED_CTA        = 'If you want to see more short hair, say yes.';
  const FIXED_DESC_CTA   = 'If you want to see more short hair styles like this, say YES in the comments.';

  // Fix dialogue in prompt
  let prompt = data.video_animation_prompt;
  prompt = prompt.replace(
    /(Dialogue \(English\):[\s\S]*?")(.*?)("|$)/i,
    (match, before, speech, end) => {
      const base = speech
        .replace(/[Ii]f you want to see more short hair[^.]*/gi, '')
        .replace(/[Ss]ay [Yy][Ee][Ss][^.]*/gi, '')
        .trim()
        .replace(/\.+$/, '');
      return `${before}${base}. ${FIXED_CTA}${end}`;
    }
  );

  // Fix post_description last sentence
  const sentences = data.post_description.split(/(?<=[.!?])\s+/).filter(s => s.trim());
  const fixedDesc = [sentences[0] || '', sentences[1] || '', FIXED_DESC_CTA].filter(Boolean).join(' ');

  // Quality score
  const sections = ['First 3 seconds','Dialogue','Facial performance','Background music','Camera','Lighting','Style'];
  const missing  = sections.filter(s => !prompt.includes(s));
  const ctaOk    = prompt.includes(FIXED_CTA);
  let score      = 100 - (missing.length * 10) - (ctaOk ? 0 : 30) - (data.post_title.length < 10 ? 10 : 0);

  return {
    video_animation_prompt: prompt,
    post_title:             data.post_title,
    post_description:       fixedDesc,
    comment_bait:           data.comment_bait,
    hashtags_instagram:     data.hashtags.instagram.join(' '),
    hashtags_tiktok:        data.hashtags.tiktok.join(' '),
    hashtags_facebook:      data.hashtags.facebook.join(' '),
    hashtags_pinterest:     data.hashtags.pinterest.join(' '),
    cta_enforced:           ctaOk ? 'AI correct' : 'JS fixed',
    quality_score:          score,
    quality_status:         score >= 70 ? 'PASS' : 'FAIL',
    missing_sections:       missing.join(', ') || 'none',
    run_timestamp:          new Date().toISOString()
  };

} catch (err) {
  return { quality_status: 'FAIL', quality_score: 0, error: err.message, raw_text: raw };
}

// Build YouTube content from existing fields — NO extra API call needed
const c = $('Parse, enforce CTA, validate').item.json;

// Extract hair style name from post_title (first 4 words as the core topic)
const titleWords = c.post_title.split(' ');
const hairTopic  = titleWords.slice(0, 5).join(' ');

// YouTube title — SEO optimized, under 70 chars
const youtubeTitle = `${c.post_title} | Short Hair 2025`;
const safetitle    = youtubeTitle.slice(0, 70);

// YouTube description — assembled from existing content, no AI needed
const youtubeDescription = [
  c.post_description,
  '',
  'If this style inspired you, give this video a LIKE and SUBSCRIBE for daily short hair inspiration.',
  '',
  '--- Chapters ---',
  '00:00 The look — first impression',
  '00:03 Hair texture and movement',
  '00:06 Why this cut is so flattering',
  '00:18 The styling secret',
  '00:35 Say yes for more short hair',
  '',
  c.hashtags_instagram.split(' ').slice(0, 10).join(', ')
].join('\n');

// YouTube tags — built from instagram hashtags + fixed short hair terms
const baseTagsRaw  = c.hashtags_instagram.split(' ').map(t => t.replace('#', ''));
const extraTags    = ['short hair 2025','hairstyles 2025','short hair ideas','short haircut women','hair transformation','beauty tips','hair goals','short hair inspo','hair tutorial','salon hair'];
const allTags      = [...new Set([...baseTagsRaw, ...extraTags])].slice(0, 30);

// Chapters
const chapters = [
  { timestamp: '00:00', title: 'The look — first impression' },
  { timestamp: '00:03', title: 'Hair texture and movement' },
  { timestamp: '00:06', title: 'Why this cut is so flattering' },
  { timestamp: '00:18', title: 'The styling secret' },
  { timestamp: '00:35', title: 'Say yes for more short hair' }
];

return {
  youtube_title:       safetitle,
  youtube_description: youtubeDescription,
  youtube_tags:        allTags.join(','),
  youtube_chapters:    chapters.map(c => `${c.timestamp} ${c.title}`).join('\n')
};

const content = $('Parse, enforce CTA, validate').item.json;
const youtube  = $('Build YouTube content (no API)').item.json;

const instagramCaption = [
  content.post_title, '',
  content.post_description, '',
  content.hashtags_instagram
].join('\n');

const tiktokCaption = [
  content.post_title, '',
  content.comment_bait, '',
  content.hashtags_tiktok
].join('\n');

const facebookPost = [
  content.post_title, '',
  content.post_description, '',
  content.comment_bait, '',
  content.hashtags_facebook
].join('\n');

const pinterestDescription = [
  content.post_title + ' — ' + content.post_description, '',
  content.hashtags_pinterest
].join('\n');

return {
  video_animation_prompt: content.video_animation_prompt,
  instagram_caption:      instagramCaption,
  tiktok_caption:         tiktokCaption,
  instagram_comment:      content.comment_bait,
  facebook_post:          facebookPost,
  pinterest_title:        content.post_title,
  pinterest_description:  pinterestDescription,
  youtube_title:          youtube.youtube_title,
  youtube_description:    youtube.youtube_description,
  youtube_tags:           youtube.youtube_tags,
  youtube_chapters:       youtube.youtube_chapters,
  run_timestamp:          content.run_timestamp,
  quality_score:          content.quality_score,
  cta_enforced:           content.cta_enforced,
  image_public_url:       $('Upload to Cloudinary').item.json.url || ''
};

return {
  run_timestamp: new Date().toISOString(),
  image_url: '', quality_score: $('Parse, enforce CTA, validate').item.json.quality_score || 0,
  cta_enforced: 'N/A — failed', video_prompt: 'FAILED',
  instagram_caption: 'FAILED — ' + ($('Parse, enforce CTA, validate').item.json.error || 'low score'),
  tiktok_caption: '', facebook_post: '', pinterest_title: '', pinterest_description: '',
  youtube_title: '', youtube_description: '', youtube_tags: '', youtube_chapters: ''
};
